        C = static_cast<uint64_t>(in_shape->GetOriginShape().GetDim(1));
        L = static_cast<uint64_t>(in_shape->GetOriginShape().GetDim(2));
    } else {
        // flatten all but last
        if (dims >= 1) {
            L = static_cast<uint64_t>(in_shape->GetOriginShape().GetDim(dims - 1));
            uint64_t nc = 1;
            for (uint32_t i = 0; i + 1 < dims; ++i) {
                nc *= static_cast<uint64_t>(in_shape->GetOriginShape().GetDim(i));
            }
            N = 1;
            C = nc;
        }
    }

    uint64_t Lpad = L + 2ULL * padding;
    uint64_t Lout = 0;
    if (Lpad >= kernel && stride > 0) {
        Lout = (Lpad - kernel) / stride + 1ULL;
    } else {
        Lout = 0;
    }

    gert::Shape *out_shape = context->GetOutputShape(0);
    std::vector<int64_t> oshape = {static_cast<int64_t>(N), static_cast<int64_t>(C), static_cast<int64_t>(Lout)};
    out_shape->SetDimNum(oshape.size());
    for (size_t i = 0; i < oshape.size(); ++i) out_shape->SetDim(i, oshape[i]);

    context->SetOutputDataType(0, in_dtype);
    return GRAPH_SUCCESS;
}

