        pipe_.InitBuffer(outQ_, OUTBUF_NUM, tileOut_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLines_ == 0 || l_ == 0 || lout_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Each block processes multiple lines of shape [L]
        for (uint64_t line = blockIdx; line < totalLines_; line += blockNum) {
            ProcessLine(line);
        }
    }

private:
    __aicore__ inline void ProcessLine(uint64_t lineIdx)
    {
        const uint64_t xLineBase = lineIdx * l_;
        const uint64_t yLineBase = lineIdx * lout_;

        uint32_t outBase = 0;
        while (outBase < lout_) {
            const uint32_t curOutLen = AscendC::Min(tileOut_, lout_ - outBase);

            // Compute GM range to copy for this tile
            // Input start index (can be negative because of padding)
            int64_t inStart = static_cast<int64_t>(outBase) * static_cast<int64_t>(s_) - static_cast<int64_t>(p_);
            uint32_t sliceLen = (curOutLen - 1u) * s_ + k_;

            // We fill whole local input slice with zeros then overlay GM range
            AscendC::LocalTensor<float> inLocal = inQ_.AllocTensor<float>();
            AscendC::LocalTensor<float> outLocal = outQ_.AllocTensor<float>();
            AscendC::Dup(inLocal, 0.0f, sliceMax_); // zero padding

            // GM copy interval:
            int64_t gmCopyStart = AscendC::Max<int64_t>(0, inStart);
            int64_t gmCopyEnd = AscendC::Min<int64_t>(static_cast<int64_t>(l_), inStart + static_cast<int64_t>(sliceLen));
            uint32_t gmCopyLen = 0;
            uint32_t localOffset = 0;
            if (gmCopyEnd > gmCopyStart) {
                gmCopyLen = static_cast<uint32_t>(gmCopyEnd - gmCopyStart);
                localOffset = static_cast<uint32_t>(gmCopyStart - inStart);
                // Copy the continuous gm segment into local offset
                AscendC::DataCopy(inLocal[localOffset], xGm_[xLineBase + static_cast<uint64_t>(gmCopyStart)], gmCopyLen);
